import functools

class Solution:
    def minCost(self, n: int) -> int:
        # Independent approach: literally search every way to split x into a+b
        # and recurse (memoized), rather than trusting the closed-form count.
        @functools.lru_cache(maxsize=None)
        def best_cost(x):
            if x == 1:
                return 0
            result = None
            for a in range(1, x):
                b = x - a
                total = a * b + best_cost(a) + best_cost(b)
                if result is None or total < result:
                    result = total
            return result
        return best_cost(n)

